"use strict";(()=>{async function s(e,t={}){let n=new Headers(t.headers);n.has("accept")||n.set("accept","application/json");let r=await fetch(e,{credentials:"same-origin",...t,headers:n});if(r.status===401)throw location.href="/app/login?next="+encodeURIComponent(location.pathname+location.search),new Error("session expired");return r}function c(){let e=document.getElementById("journal-groups");e&&document.querySelectorAll(".journal-filter").forEach(t=>{t.addEventListener("change",()=>{e.classList.toggle(`journal-hide-${t.value}`,!t.checked)})})}async function i(e,t){let n=e.getAttribute("href");if(!n)return;let r=e.textContent;e.textContent="Carregando\u2026";try{let a=await s(n);if(!a.ok)throw new Error("journal load-more "+a.status);let o=await a.json();if(o.html&&t.insertAdjacentHTML("beforeend",o.html),o.next_url){let l=o.next_url.includes("?")?"&":"?";e.setAttribute("href",`${o.next_url}${l}carry=${encodeURIComponent(o.last_label??"")}`),e.textContent=r}else e.remove()}catch(a){e.textContent=r,console.warn("journal: load-more failed",a)}}function u(){let e=document.getElementById("journal-groups"),t=document.getElementById("journal-load-more");!t||!e||t.addEventListener("click",n=>{n.preventDefault(),i(t,e)})}c();u();})();
